import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'
import * as BaseInput from '../../base-ui/input'

// MODEL

export const InputStyleOptions = S.Struct({
  className: S.optional(S.String),
})
export type InputStyleOptions = typeof InputStyleOptions.Type

// VIEW

export type InputAttributes<Message> = BaseInput.InputAttributes<Message>

export type ViewConfig<Message> = Omit<
  BaseInput.ViewConfig<Message>,
  'toView'
> &
  InputStyleOptions &
  Readonly<{
    toView: (attributes: InputAttributes<Message>) => Html
  }>

export const inputBaseClassName =
  'h-8 w-full min-w-0 rounded-lg border border-input bg-transparent px-2.5 py-1 text-base transition-colors outline-none file:inline-flex file:h-6 file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:cursor-not-allowed disabled:bg-input/50 disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 md:text-sm dark:bg-input/30 dark:disabled:bg-input/80 dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40'

export const inputClassName = ({ className }: InputStyleOptions = {}): string =>
  cn(inputBaseClassName, className)

const shadcnAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  className: string | undefined,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', 'input'),
  h.Class(inputClassName({ className })),
]

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, className, ...baseConfig } = config

  return BaseInput.view<Message>({
    ...baseConfig,
    toView: attributes =>
      toView({
        input: [...attributes.input, ...shadcnAttributes(h, className)],
      }),
  })
}

import type { Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { view as Badge } from '../badge'
import { view as Button } from '../button'
import { ButtonGroup } from '../button-group'
import {
  Field,
  FieldContent,
  FieldDescription,
  FieldGroup,
  FieldLabel,
} from '../field'
import {
  InputGroup,
  InputGroupAddon,
  InputGroupInput,
  InputGroupText,
} from '../input-group'
import { view as Input } from './index'

const input = (
  config: Readonly<{
    id?: string
    type?: string
    placeholder?: string
    value?: string
    disabled?: boolean
    invalid?: boolean
    required?: boolean
  }>,
): Html => {
  const h = html<never>()

  return Input<never>({
    id: config.id,
    type: config.type,
    value: config.value,
    placeholder: config.placeholder,
    isDisabled: config.disabled,
    isInvalid: config.invalid,
    isRequired: config.required,
    toView: attributes => h.input([...attributes.input]),
  })
}

export const InputDemo = (): Html =>
  input({
    id: 'input-demo-api-key',
    type: 'password',
    placeholder: 'sk-...',
  })

export const InputBasic = (): Html =>
  input({
    id: 'input-basic',
    placeholder: 'Enter text',
  })

export const InputDisabled = (): Html =>
  input({
    id: 'input-demo-disabled',
    disabled: true,
    type: 'email',
    placeholder: 'Email',
  })

export const InputInvalid = (): Html =>
  input({
    id: 'input-invalid',
    invalid: true,
    placeholder: 'Error',
  })

export const InputFile = (): Html =>
  input({
    id: 'picture',
    type: 'file',
  })

export const InputRequired = (): Html =>
  input({
    id: 'input-required',
    required: true,
    placeholder: 'This field is required',
  })

const button = (text: string, variant: 'default' | 'outline' = 'default') =>
  Button<never>({
    variant,
    toView: attributes => {
      const h = html<never>()

      return h.button([...attributes.button], [text])
    },
  })

export const InputField = (): Html =>
  Field<never>({
    className: 'w-full max-w-sm',
    children: [
      FieldLabel<never>({
        htmlFor: 'input-field-username',
        children: ['Username'],
      }),
      input({
        id: 'input-field-username',
        placeholder: 'shadcn',
      }),
      FieldDescription<never>({
        children: ['Choose a unique username for your account.'],
      }),
    ],
  })

export const InputFieldGroup = (): Html => {
  const h = html<never>()

  return FieldGroup<never>({
    className: 'w-full max-w-sm',
    children: [
      Field<never>({
        children: [
          FieldLabel<never>({
            htmlFor: 'input-group-name',
            children: ['Name'],
          }),
          input({ id: 'input-group-name', placeholder: 'Evil Rabbit' }),
        ],
      }),
      Field<never>({
        children: [
          FieldLabel<never>({
            htmlFor: 'input-group-email',
            children: ['Email'],
          }),
          input({
            id: 'input-group-email',
            type: 'email',
            placeholder: 'm@example.com',
          }),
          FieldDescription<never>({
            children: ["We'll send updates to this address."],
          }),
        ],
      }),
      h.div(
        [h.Class('flex gap-2')],
        [button('Reset', 'outline'), button('Submit')],
      ),
    ],
  })
}

export const InputInline = (): Html =>
  Field<never>({
    orientation: 'horizontal',
    className: 'w-full max-w-md items-end',
    children: [
      FieldContent<never>({
        children: [
          FieldLabel<never>({
            htmlFor: 'input-inline-search',
            children: ['Search'],
          }),
          input({
            id: 'input-inline-search',
            type: 'search',
            placeholder: 'Search documentation...',
          }),
        ],
      }),
      button('Search'),
    ],
  })

export const InputGrid = (): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('grid w-full max-w-md grid-cols-2 gap-4')],
    [
      Field<never>({
        children: [
          FieldLabel<never>({
            htmlFor: 'input-grid-first',
            children: ['First Name'],
          }),
          input({ id: 'input-grid-first', placeholder: 'Evil' }),
        ],
      }),
      Field<never>({
        children: [
          FieldLabel<never>({
            htmlFor: 'input-grid-last',
            children: ['Last Name'],
          }),
          input({ id: 'input-grid-last', placeholder: 'Rabbit' }),
        ],
      }),
    ],
  )
}

export const InputBadge = (): Html =>
  Field<never>({
    className: 'w-full max-w-sm',
    children: [
      FieldLabel<never>({
        htmlFor: 'input-badge-webhook',
        children: [
          'Webhook URL',
          Badge<never>({
            variant: 'secondary',
            toView: attributes => {
              const h = html<never>()

              return h.span([...attributes.badge], ['Beta'])
            },
          }),
        ],
      }),
      input({
        id: 'input-badge-webhook',
        type: 'url',
        placeholder: 'https://example.com/webhook',
      }),
    ],
  })

export const InputGroupExample = (): Html =>
  Field<never>({
    className: 'w-full max-w-sm',
    children: [
      FieldLabel<never>({
        htmlFor: 'input-group-website',
        children: ['Website URL'],
      }),
      InputGroup<never>({
        children: [
          InputGroupAddon<never>({
            children: [InputGroupText<never>({ children: ['https://'] })],
          }),
          InputGroupInput<never>({
            id: 'input-group-website',
            placeholder: 'shadcn.com',
          }),
        ],
      }),
    ],
  })

export const InputButtonGroup = (): Html =>
  Field<never>({
    className: 'w-full max-w-sm',
    children: [
      FieldLabel<never>({
        htmlFor: 'input-button-group-search',
        children: ['Search'],
      }),
      ButtonGroup<never>({
        children: [
          input({
            id: 'input-button-group-search',
            type: 'search',
            placeholder: 'Search...',
          }),
          button('Search'),
        ],
      }),
    ],
  })

